INSERT INTO subgroup (id, group_id, name, description, profile_image_url, join_type, join_password, status, member_count, created_at, updated_at)
WITH cfg AS (
  SELECT ARRAY['점심', '야식', '회식', '카페', '러닝', '스터디', '프로젝트', '탐방']::TEXT[] AS topics
)
SELECT
  sg.id,
  sg.group_id,
  '더미팀' || '-' || cfg.topics[((sg.seq - 1) % CARDINALITY(cfg.topics)) + 1] || '-' || sg.group_seq || '-' || sg.subgroup_index,
  '관심사 기반 소규모 모임입니다. 일정 조율 후 함께 방문해요.',
  CASE WHEN MOD(sg.seq, 3) = 0 THEN NULL ELSE 'https://cdn.tasteam.kr/subgroups' || '/' || '546d8cf5709d' || '/' || sg.id || '.jpg' END,
  CASE WHEN MOD(sg.seq, 5) = 0 THEN 'PASSWORD' ELSE 'OPEN' END,
  CASE WHEN MOD(sg.seq, 5) = 0 THEN 'sg-pass' || '-' || sg.group_seq || '-' || sg.subgroup_index ELSE NULL END,
  'ACTIVE',
  0,
  NOW() - ((sg.seq % 300) || ' days')::INTERVAL,
  NOW() - ((sg.seq % 300) || ' days')::INTERVAL
FROM tmp_dummy_subgroup sg
CROSS JOIN cfg
ORDER BY sg.seq;

