JOIN generate_series(0, 29) AS off(member_offset) ON TRUE
JOIN tmp_dummy_member m
  ON m.seq = (((((g.seq * 37) % 10000) + off.member_offset) % 10000) + 1)
ON CONFLICT DO NOTHING;

