  m.id,
  'TEXT',
  CASE     WHEN MOD(msg.message_idx, 5) IN (0, 1) THEN '더미 채팅 메시지' || ' #' || (((cr.seq - 1) * 167) + msg.message_idx) || ' ' || cfg.short_msgs[((msg.message_idx - 1) % CARDINALITY(cfg.short_msgs)) + 1]     ELSE '더미 채팅 메시지' || ' #' || (((cr.seq - 1) * 167) + msg.message_idx) || ' ' || cfg.long_msgs[((msg.message_idx - 1) % CARDINALITY(cfg.long_msgs)) + 1]   END,
  NOW() - ((cr.seq % 90) || ' days')::INTERVAL
FROM tmp_dummy_chat_room cr
CROSS JOIN cfg
JOIN tmp_dummy_subgroup sg ON sg.id = cr.subgroup_id
JOIN generate_series(1, 167) AS msg(message_idx) ON TRUE
JOIN tmp_dummy_member m
  ON m.seq = ((((sg.group_seq * 37) % 10000) + ((((sg.group_seq * 31 + sg.subgroup_index * 17) % 30) + ((msg.message_idx - 1) % 30)) % 30)) % 10000) + 1
ORDER BY cr.seq, msg.message_idx;

-- Update last_read_message_id for 70% of chat_room_member rows
UPDATE chat_room_member crm
SET last_read_message_id = latest.max_id
FROM (
  SELECT chat_room_id, MAX(id) AS max_id
  FROM chat_message
  WHERE chat_room_id IN (SELECT id FROM tmp_dummy_chat_room)
  GROUP BY chat_room_id
) AS latest
WHERE crm.chat_room_id = latest.chat_room_id
  AND (crm.id % 10) < 7;

-- Reviews
INSERT INTO tmp_dummy_review (seq, id, member_id, restaurant_id, group_id, subgroup_id, is_recommended)
SELECT
  rv.seq,
  nextval(pg_get_serial_sequence('review', 'id')),
  m.id,
  rest.id,
  g.id,
  sg.id,
  (MOD(rv.seq - 1, 4) != 0)
FROM generate_series(1, 300000) AS rv(seq)
JOIN tmp_dummy_member m
  ON m.seq = (CASE WHEN MOD(rv.seq - 1, 10) < 8 THEN ((rv.seq - 1) % 2000) + 1 ELSE 2000 + (((rv.seq - 1) % 8000) + 1) END)
JOIN tmp_dummy_group g
  ON g.seq = (((rv.seq - 1) % 1500) + 1)
LEFT JOIN tmp_dummy_subgroup sg
  ON sg.group_id = g.id AND sg.subgroup_index = (((rv.seq - 1) % 4) + 1)
JOIN tmp_dummy_restaurant rest
  ON rest.seq = (CASE WHEN MOD(rv.seq - 1, 10) < 6 THEN ((rv.seq - 1) % 1000) + 1 ELSE 1000 + (((rv.seq - 1) % 9000) + 1) END)
ORDER BY rv.seq;

WITH cfg AS (
  SELECT ARRAY['직원 응대가 친절하고 음식이 빨리 나왔습니다.', '대표 메뉴의 완성도가 높고 재료 신선도가 좋았습니다.', '매장 동선이 편하고 좌석 간격이 넉넉했습니다.']::TEXT[] AS positive_lines,
         ARRAY['피크타임에는 대기 시간이 길어질 수 있습니다.', '일부 메뉴는 간이 조금 강하게 느껴졌습니다.', '주차가 다소 불편한 편이었습니다.']::TEXT[] AS negative_lines,
         ARRAY['동료들과 점심 모임으로 방문했습니다.', '퇴근 후 소규모 모임으로 다녀왔습니다.', '주말 오후에 가족과 함께 이용했습니다.', '혼밥으로 방문했는데 부담이 적었습니다.']::TEXT[] AS context_lines
)
INSERT INTO review (id, member_id, restaurant_id, group_id, subgroup_id, is_recommended, content, created_at, updated_at)
SELECT
  rv.id,
  rv.member_id,
  rv.restaurant_id,
  rv.group_id,
  rv.subgroup_id,
  rv.is_recommended,
  CASE     WHEN MOD(rv.seq, 4) = 0 THEN '더미 리뷰 내용입니다.' || ' ' || cfg.context_lines[((rv.seq - 1) % CARDINALITY(cfg.context_lines)) + 1] || ' ' || cfg.positive_lines[((rv.seq - 1) % CARDINALITY(cfg.positive_lines)) + 1] || ' ' || cfg.negative_lines[((rv.seq - 1) % CARDINALITY(cfg.negative_lines)) + 1]     WHEN MOD(rv.seq, 4) = 1 THEN cfg.context_lines[((rv.seq - 1) % CARDINALITY(cfg.context_lines)) + 1] || ' ' || cfg.positive_lines[((rv.seq - 1) % CARDINALITY(cfg.positive_lines)) + 1]     WHEN MOD(rv.seq, 4) = 2 THEN '더미 리뷰 내용입니다.' || ' ' || cfg.negative_lines[((rv.seq - 1) % CARDINALITY(cfg.negative_lines)) + 1]     ELSE '더미 리뷰 내용입니다.' || ' 방문 ' || rv.seq || '회차 리뷰입니다.'   END,
  NOW() - ((rv.seq % 180) || ' days')::INTERVAL,
  NOW() - ((rv.seq % 180) || ' days')::INTERVAL
FROM tmp_dummy_review rv
CROSS JOIN cfg
ORDER BY rv.seq;

-- Review keywords (keyword 테이블이 비어있으면 skip)
DO $$
DECLARE
  keyword_count INTEGER;
  max_per_review INTEGER;
BEGIN
  SELECT COUNT(*) INTO keyword_count FROM tmp_dummy_keyword;
  IF keyword_count > 0 THEN
    max_per_review := LEAST(3, keyword_count);
    INSERT INTO review_keyword (review_id, keyword_id)
    SELECT
      rv.id,
      kw.id
    FROM tmp_dummy_review rv
    JOIN generate_series(0, max_per_review - 1) AS offs(off)
      ON offs.off < (1 + ((rv.seq - 1) % max_per_review))
    JOIN tmp_dummy_keyword kw
      ON kw.seq = ((((rv.seq - 1) % keyword_count) + offs.off) % keyword_count) + 1
    ON CONFLICT DO NOTHING;
  END IF;
END $$;

-- Restaurant review analysis
INSERT INTO restaurant_review_sentiment (restaurant_id, vector_epoch, model_version, positive_count, negative_count, neutral_count, positive_percent, negative_percent, neutral_percent, analyzed_at)
SELECT
  r.id,
  0,
  'dummy-v1',
  ((r.seq - 1) % 10) + 1,
  2,
  1,
  60,
  20,
  20,
  NOW()
FROM tmp_dummy_restaurant r
ON CONFLICT (restaurant_id) DO NOTHING;

INSERT INTO restaurant_review_summary (restaurant_id, vector_epoch, model_version, summary_json, analyzed_at)
SELECT
  r.id,
  0,
  'dummy-v1',
  '{"summary":"더미 리뷰 요약입니다.","highlights":["맛있다","친절하다"]}'::jsonb,
  NOW()
FROM tmp_dummy_restaurant r
ON CONFLICT DO NOTHING;

-- Notifications
WITH cfg AS (
  SELECT ARRAY['CHAT', 'SYSTEM', 'NOTICE']::TEXT[] AS notif_types,
         ARRAY['새 채팅이 도착했어요', '즐겨찾기한 식당에 새 리뷰가 올라왔어요', '관심 그룹 공지 확인해보세요', '지금 인기 많은 맛집을 확인해보세요']::TEXT[] AS title_pool,
         ARRAY['놓치지 않도록 지금 바로 확인해보세요.', '최근 반응이 좋아 빠르게 마감될 수 있어요.', '새로운 멤버의 추천 리뷰가 등록됐습니다.', '설정에서 알림 유형을 자유롭게 조정할 수 있어요.']::TEXT[] AS body_pool
)
INSERT INTO notification (member_id, notification_type, title, body, deep_link, event_id, created_at)
SELECT
  m.id,
  cfg.notif_types[(MOD(ns.seq, CARDINALITY(cfg.notif_types)) + 1)],
  '더미 알림 제목' || ' · ' || cfg.title_pool[((ns.seq) % CARDINALITY(cfg.title_pool)) + 1],
  '더미 알림 내용입니다.' || ' ' || cfg.body_pool[((ns.seq) % CARDINALITY(cfg.body_pool)) + 1] || ' (ref:' || (ns.seq + 1) || ')',
  CASE cfg.notif_types[(MOD(ns.seq, CARDINALITY(cfg.notif_types)) + 1)]     WHEN 'CHAT' THEN '/chat/rooms/' || ((ns.seq % 6000) + 1)     WHEN 'NOTICE' THEN '/groups/' || ((ns.seq % 1500) + 1)     ELSE '/notifications'   END,
  'dummy' || '-' || '546d8cf5709d' || '-' || ns.seq || '-' || SUBSTR(MD5('546d8cf5709d' || '-' || ns.seq::TEXT), 1, 8),
  NOW() - ((ns.seq % 90) || ' days')::INTERVAL
FROM generate_series(0, 399999) AS ns(seq)
JOIN tmp_dummy_member m
  ON m.seq = ((ns.seq % 10000) + 1)
CROSS JOIN cfg
ON CONFLICT (event_id) WHERE event_id IS NOT NULL DO NOTHING;

-- Member favorite restaurants
INSERT INTO member_favorite_restaurant (member_id, restaurant_id, created_at)
SELECT
  m.id,
  r.id,
  NOW() - ((fs.seq % 180) || ' days')::INTERVAL
FROM generate_series(0, 99999) AS fs(seq)
JOIN tmp_dummy_member m
  ON m.seq = ((fs.seq % 10000) + 1)
JOIN tmp_dummy_restaurant r
  ON r.seq = (((fs.seq / 10000) % 10000) + 1)
ON CONFLICT DO NOTHING;

-- Subgroup favorite restaurants
INSERT INTO subgroup_favorite_restaurant (member_id, subgroup_id, restaurant_id, created_at)
SELECT
  m.id,
  sg.id,
  r.id,
  NOW() - ((sfs.seq % 180) || ' days')::INTERVAL
FROM generate_series(0, 999) AS sfs(seq)
JOIN tmp_dummy_member m
  ON m.seq = ((sfs.seq % 10000) + 1)
JOIN tmp_dummy_subgroup sg
  ON sg.seq = (((sfs.seq / 10000) % 6000) + 1)
JOIN tmp_dummy_restaurant r
  ON r.seq = (((sfs.seq / 60000000) % 10000) + 1)
ON CONFLICT DO NOTHING;

-- Load-test bootstrap fixture for k6/locust scripts (phase1_test / locustfile)
