  identifier TEXT NOT NULL,
  nickname TEXT NOT NULL,
  member_id BIGINT
) ON COMMIT DROP;
INSERT INTO tmp_loadtest_users (idx, identifier, nickname)
SELECT
  gs,
  format('test-user-%s', lpad(gs::text, 3, '0')) AS identifier,
  format('부하테스트계정%s', gs) AS nickname
FROM generate_series(1, 1000) AS gs;

-- Load-test members + OAuth account
INSERT INTO member (id, email, nickname, status, role, profile_image_url, introduction, last_login_at, agreed_terms_at, agreed_privacy_at, created_at, updated_at)
SELECT
  nextval('member_seq'),
  tu.identifier || '@test.local',
  tu.nickname,
  'ACTIVE',
  'USER',
  NULL,
  NULL,
  NOW(),
  NOW() - INTERVAL '1 day',
  NOW() - INTERVAL '1 day',
  NOW(),
  NOW()
FROM tmp_loadtest_users tu
ON CONFLICT (email) DO NOTHING;

UPDATE tmp_loadtest_users tu
SET member_id = m.id
FROM member m
WHERE m.email = tu.identifier || '@test.local';

INSERT INTO member_oauth_account (id, member_id, provider, provider_user_id, provider_user_email, created_at)
