DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pgcrypto') THEN
    RAISE WARNING 'pgcrypto extension not found: group_auth_code for load-test group skipped';
    RETURN;
  END IF;

  DELETE FROM group_auth_code WHERE group_id = 2002;
  INSERT INTO group_auth_code (id, group_id, code, created_at) VALUES (nextval('group_auth_code_seq'), 2002, crypt('LOCAL-1234', gen_salt('bf', 12)), NOW());
END $$;

